const input = $input.first().json;

function buildDateFilter(periodo) {
  if (periodo === 'hoy') return `fecha::date = CURRENT_DATE`;
  if (periodo === 'ayer') return `fecha::date = CURRENT_DATE - 1`;
  if (periodo === 'semana') return `fecha >= NOW() - INTERVAL '7 days'`;
  if (periodo === 'semana_pasada') return `fecha >= NOW() - INTERVAL '14 days' AND fecha < NOW() - INTERVAL '7 days'`;
  if (periodo === 'mes') return `DATE_TRUNC('month', fecha) = DATE_TRUNC('month', NOW())`;
  if (periodo === 'mes_pasado') return `DATE_TRUNC('month', fecha) = DATE_TRUNC('month', NOW() - INTERVAL '1 month')`;
  return `fecha::date = CURRENT_DATE`;
}

const f1 = buildDateFilter(input.periodo1);
const f2 = buildDateFilter(input.periodo2);

const query = `SELECT '${input.periodo1}' AS periodo, categoria, SUM(monto) AS total FROM gastos WHERE phone_number = '${input.phone_number}' AND ${f1} GROUP BY categoria UNION ALL SELECT '${input.periodo2}' AS periodo, categoria, SUM(monto) AS total FROM gastos WHERE phone_number = '${input.phone_number}' AND ${f2} GROUP BY categoria ORDER BY periodo, total DESC`;

return [{ json: { query, periodo1: input.periodo1, periodo2: input.periodo2 } }];

const items = $input.all();
const meta = $('Code: Build Query').first().json;
const rows = items.filter(item => item.json.periodo != null);

if (rows.length === 0) {
  return [{ json: { output: 'No hay gastos en ninguno de los dos periodos para comparar.' } }];
}

const labels = { hoy: 'Hoy', ayer: 'Ayer', semana: 'Esta semana', semana_pasada: 'Semana pasada', mes: 'Este mes', mes_pasado: 'Mes pasado' };

function formatPeriodo(periodo, data) {
  const label = labels[periodo] || periodo;
  const cats = data.filter(r => r.json.periodo === periodo);
  if (cats.length === 0) return `${label}: Sin gastos`;
  const total = cats.reduce((sum, r) => sum + parseFloat(r.json.total), 0);
  const lines = cats.map(r => `  - ${r.json.categoria}: $${parseFloat(r.json.total).toFixed(2)}`).join('\n');
  return `${label}: $${total.toFixed(2)}\n${lines}`;
}

const p1 = formatPeriodo(meta.periodo1, rows);
const p2 = formatPeriodo(meta.periodo2, rows);

const t1 = rows.filter(r => r.json.periodo === meta.periodo1).reduce((s, r) => s + parseFloat(r.json.total), 0);
const t2 = rows.filter(r => r.json.periodo === meta.periodo2).reduce((s, r) => s + parseFloat(r.json.total), 0);
const diff = t1 - t2;
const diffStr = diff >= 0 ? `+$${diff.toFixed(2)}` : `-$${Math.abs(diff).toFixed(2)}`;

const output = `Comparacion:\n\n${p1}\n\n${p2}\n\nDiferencia: ${diffStr}`;
return [{ json: { output } }];
